import { useState, useEffect } from 'react';
import { Card, Form, Input, Button, Typography, Modal, Radio, message, Divider, Col, Breadcrumb } from 'antd';
import { getSkKey, resetSkKey, updateSkKey } from '@/services/api';
import { PageContainer } from '@ant-design/pro-layout';
import { t } from '@/global';
import { EyeInvisibleTwoTone, EyeTwoTone } from '@ant-design/icons/lib/icons';

const KeyPage: React.FC = () => {
  const [cardForm] = Form.useForm();
  const [modalForm] = Form.useForm();
  const [editModalVisible, setEditModalVisible] = useState(false);
  const [modalOption, setModalOption] = useState("reset");
  const [isLoading, setIsLoading] = useState(true);
  const [privateInputVisible, setprivateInputVisible] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const data = await getSkKey();
        cardForm.setFieldsValue({
          pri_key: data.pri_key,
          pub_key: data.pub_key,
        });
      } catch (error) {
        message.error("Failed to fetch key: " + error);
      }
      setIsLoading(false);
    })();
  }, []);

  const handleOpenEditModal = () => {
    setEditModalVisible(true);
  };

  const handleModalOptionChange = (e: any) => {
    setModalOption(e.target.value);
  };

  const handlePrivateInputVisibleChanged = () => {
    setprivateInputVisible(!privateInputVisible);
  }

  const handleModalSubmit = async () => {
    try {
      await modalForm.validateFields();
    } catch (err) {
      console.error(err);
      return;
    }

    const msg = "Key has been updated in hbbs successfully, please take care of hbbr manually if hbbr runs on the other machine or uses special port."

    if (modalOption === 'reset') {
      try {
        const newKey = await resetSkKey();
        cardForm.setFieldsValue({
          pri_key: newKey.pri_key,
          pub_key: newKey.pub_key,
        });
        message.success(msg);
        setEditModalVisible(false);
      } catch (e) {
        message.error(e as any);
      }
    } else {
      const values = modalForm.getFieldsValue(['pri_key']);
      try {
        await updateSkKey(values.pri_key);
        message.success(msg);
        setEditModalVisible(false);
        const newKey = await getSkKey();
        cardForm.setFieldsValue({
          pri_key: newKey.pri_key,
          pub_key: newKey.pub_key,
        });
        modalForm.resetFields();
      } catch (e) {
        message.error(e as any);
      }
    }
  };

  return (
    (<PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.Settings', true) },
          { title: t('menu.Settings.Key', true) },
        ]} />
      )}
    >
      {isLoading ? null : (<Card>
        <Form form={cardForm} labelCol={{ span: 24, offset: 0 }} labelAlign={"left"}>
          <Form.Item label={t("pages.Settings.KeyPage.privateKey", true, "Private Key")}>
            <Form.Item name="pri_key" noStyle>
              <Input
                disabled
                type={privateInputVisible ? "" : "password"}
                suffix={
                  <Col>
                    {privateInputVisible ?
                      <EyeTwoTone onClick={handlePrivateInputVisibleChanged} />
                      : <EyeInvisibleTwoTone onClick={handlePrivateInputVisibleChanged} />}
                    <Typography.Text copyable={{ text: cardForm.getFieldValue('pri_key') }} />
                  </Col>
                }
              />
            </Form.Item>
          </Form.Item>
          <Form.Item label={t("pages.Settings.KeyPage.publicKey", true, "Public Key")}>
            {/* <Form.Item label={t("Public Key")}> */}
            <Form.Item name="pub_key" >
              <Input
                disabled
                suffix={<Typography.Text copyable={{ text: cardForm.getFieldValue('pub_key') }} />}
              />
            </Form.Item>
          </Form.Item>
          <Form.Item>
            <Button danger type="primary" onClick={handleOpenEditModal}>
              {t('Edit')}
            </Button>
          </Form.Item>
        </Form>
        <Modal title={t("pages.Settings.KeyPage.editKey", true, "Edit Key")} open={editModalVisible} onOk={handleModalSubmit} onCancel={() => setEditModalVisible(false)}>
          <Radio.Group defaultValue="reset" onChange={handleModalOptionChange}>
            <Radio value="reset">{t('pages.Settings.KeyPage.reset', true, 'Reset')}</Radio>
            <Radio value="custom">{t('pages.Settings.KeyPage.custom', true, 'Custom')}</Radio>
          </Radio.Group>
          {modalOption === "custom" && (
            <>
              <Divider />
              <Form form={modalForm}>
                <Form.Item rules={[{ required: true, whitespace: true, message: t('pages.Settings.KeyPage.pleaseInputPrivateKey', true, 'Please input your private key!') }]}
                  label={t("pages.Settings.KeyPage.privateKey", true, "Private Key")} name="pri_key">
                  <Input />
                </Form.Item>
              </Form>
            </>
          )}
        </Modal>
      </Card>)
      }
    </PageContainer >)
  );
};

export default KeyPage;
